class Solution:
    def countTexts(self, pressedKeys):
        MOD = 10**9 + 7
        four = {'7', '9'}
        i = 0
        n = len(pressedKeys)
        result = 1
        while i < n:
            j = i
            while j < n and pressedKeys[j] == pressedKeys[i]:
                j += 1
            L = j - i
            g = 4 if pressedKeys[i] in four else 3
            dp = [0] * (L + 1)
            dp[0] = 1
            for x in range(1, L + 1):
                for step in range(1, g + 1):
                    if x - step >= 0:
                        dp[x] = (dp[x] + dp[x - step]) % MOD
            result = (result * dp[L]) % MOD
            i = j
        return result

