class Solution:
    def countTexts(self, pressedKeys):
        MOD = 10**9 + 7
        n = len(pressedKeys)
        dp = [0] * (n + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            ch = pressedKeys[i - 1]
            g = 4 if ch in ('7', '9') else 3
            total = 0
            for step in range(1, g + 1):
                k = i - step
                if k >= 0 and pressedKeys[k:i] == ch * step:
                    total += dp[k]
            dp[i] = total % MOD
        return dp[n]

