var countTexts = function(pressedKeys) {
    const MOD = 1000000007n;
    const n = pressedKeys.length;
    const dp = new Array(n + 1).fill(0n);
    dp[0] = 1n;
    for (let i = 1; i <= n; i++) {
        const ch = pressedKeys[i - 1];
        const g = (ch === '7' || ch === '9') ? 4 : 3;
        let total = 0n;
        for (let step = 1; step <= g; step++) {
            const k = i - step;
            if (k < 0) break;
            let same = true;
            for (let t = k; t < i; t++) {
                if (pressedKeys[t] !== ch) { same = false; break; }
            }
            if (same) total += dp[k];
        }
        dp[i] = total % MOD;
    }
    return Number(dp[n]);
};
